use indexmap::IndexMap;

struct MyStruct {
    map: IndexMap<String, i32>,
}

impl MyStruct {
    fn get_vec(&self) -> Vec<i32> {
        if self.map.is_empty() {
            vec![]
        } else {
            let mut result = Vec::with_capacity(self.map.len());
            for v in self.map.values() {
                result.push(*v);
            }
            result
        }
    }
}

fn main() {
    let mut s = MyStruct { map: IndexMap::new() };
    s.map.insert("one".into(), 1);
    s.map.insert("two".into(), 2);
    println!("{:?}", s.get_vec());
}
